--- a/src/MountManager.php
+++ b/src/MountManager.php
@@ -117,6 +117,23 @@ class MountManager implements FilesystemOperator

     public function listContents(string $location, bool $deep = self::LIST_SHALLOW): DirectoryListing
     {
+        if (strpos($location, '://') < 1) {
+            $allListings = [];
+            foreach ($this->filesystems as $mountIdentifier => $filesystem) {
+                $allListings[] = $filesystem
+                    ->listContents('', $deep)
+                    ->map(function (StorageAttributes $attributes) use ($mountIdentifier) {
+                        return $attributes->withPath(sprintf('%s://%s', $mountIdentifier, $attributes->path()));
+                    });
+            }
+
+            return new DirectoryListing((static function () use ($allListings): \Generator {
+                foreach ($allListings as $listing) {
+                    yield from $listing;
+                }
+            })());
+        }
+
         /** @var FilesystemOperator $filesystem */
         [$filesystem, $path, $mountIdentifier] = $this->determineFilesystemAndPath($location);
